[
  {
    "idea": "Inverse correlation between e-commerce returns and consumer sentiment",
    "data": {
      "source": "FedEx and UPS return volume data, University of Michigan Consumer Sentiment Index",
      "type": "api",
      "frequency": "monthly",
      "stable": true
    },
    "behavior": "When consumer sentiment declines, e-commerce return volumes increase as consumers are more likely to send back online purchases, signaling weakening consumer demand.",
    "market_impact": {
      "direction": "bearish",
      "sector": "XLY",
      "rationale": "Consumer discretionary stocks are sensitive to changes in consumer confidence and spending patterns."
    },
    "trade_logic": {
      "entry": "If consumer sentiment index decreases 5% month-over-month and e-commerce return volume increases 10% month-over-month",
      "exit": "If consumer sentiment index increases 5% month-over-month or e-commerce return volume decreases 10% month-over-month",
      "expected_frequency": "medium"
    }
  }
]
